mapper.select:
SELECT player_id,p.team_id,name,position,back_number,img_url,t.team_name,t.emblem
FROM KLeague_Player p 
JOIN KLeague_Team t ON p.team_id=t.team_id

	p.team_id=#{team_id}
	AND position=#{position}

ORDER BY ${column}
OFFSET #{start} ROWS FETCH NEXT 24 ROWS ONLY

SELECT CEIL(COUNT(*)/24.0)
FROM KLeague_Player p 
JOIN KLeague_Team t ON p.team_id=t.team_id

	p.team_id=#{team_id}
	AND position=#{position}
